const hmacResult = $json;
if (!hmacResult.valid) {
  throw new Error('HMAC invalido: assinatura recusada pelo backend');
}
const webhookData = $('Webhook Trigger').item.json;
const normalized_text = webhookData.normalized_text || '';
const provider_chain = webhookData.provider_chain || [];
const ingestion_id = webhookData.ingestion_id || '';
const shared_context = webhookData.shared_context || {};
if (!normalized_text) {
  throw new Error('Campo normalized_text ausente no payload');
}
if (!provider_chain || provider_chain.length === 0) {
  throw new Error('Campo provider_chain ausente ou vazio no payload');
}
return [{ json: { normalized_text, provider_chain, ingestion_id, shared_context, hmac_valid: true } }];

const data = $json;
const provider = data.provider_chain[0];
const systemPrompt = 'Você é o Auditor Documental Sênior do sistema GCA.

Você é a 8ª persona do GCA, com role distinto das 7 personas técnicas:
- Você lê o documento completo (não recortes)
- Você orienta a equipe técnica antes da análise começar
- Você tem permissão EXPLÍCITA de declarar incerteza
- Você NÃO improvisa quando faltam insumos

SEUS 6 OUTPUTS OBRIGATÓRIOS (em UMA resposta JSON):

1. SUMMARY (≤ 500 tokens)
   Visão executiva: objetivo, domínio, módulos principais, tipo de entrega.

2. CHUNK_TAGS (multi-label)
   Para cada chunk_id recebido, atribua tags de quais especialistas devem revisar.
   Personas técnicas: GP, ARQ, DBA, DEV, QA, UX, UI

3. HIGHLIGHTS (atenção dirigida por persona)
   Para cada uma das 7 personas técnicas, liste 1-3 pontos críticos.

4. AUDIT_FINDINGS (seu OCG-parcial — auditoria documental)
   Avalie: completude, consistência interna, clareza, estrutura, qualidade.

5. BACKLOG_TO_SPECIALISTS
   Incertezas resolvíveis por LLM. Limite absoluto: 10 itens.

6. QUESTIONNAIRE_TO_HUMAN
   Perguntas para validadores humanos (precisa info não no documento).

RETORNE APENAS JSON VÁLIDO (sem markdown, sem ```).';
const userMessage = JSON.stringify({ project_size_mode: data.shared_context.project_size_mode || 'small', normalized_text: data.normalized_text, shared_context: data.shared_context });
let requestBody;
const providerType = (provider.provider_type || '').toLowerCase();
if (providerType === 'anthropic') {
  requestBody = { model: provider.model, max_tokens: 6000, temperature: 0.1, system: systemPrompt, messages: [{ role: 'user', content: userMessage }] };
} else {
  requestBody = { model: provider.model, max_tokens: 6000, temperature: 0.1, messages: [{ role: 'system', content: systemPrompt }, { role: 'user', content: userMessage }] };
}
return [{ json: { provider, requestBody, ingestion_id: data.ingestion_id } }];

const llmResponse = $json;
const prevData = $('Montar Prompt').item.json;
let rawContent = '';
if (llmResponse.content && llmResponse.content[0] && llmResponse.content[0].text) {
  rawContent = llmResponse.content[0].text;
} else if (llmResponse.choices && llmResponse.choices[0] && llmResponse.choices[0].message) {
  rawContent = llmResponse.choices[0].message.content;
} else {
  rawContent = JSON.stringify(llmResponse);
}
let parsed = {};
try {
  parsed = JSON.parse(rawContent);
} catch (e) {
  const match = rawContent.match(/\{[\s\S]*\}/);
  if (match) { try { parsed = JSON.parse(match[0]); } catch (e2) { parsed = {}; } }
}
const findings = parsed.audit_findings || {};
const findingsCount = Array.isArray(findings) ? findings.length : Object.keys(findings).length;
const personaOutput = {
  persona_tag: 'AUD',
  persona_name: 'Auditor Documental',
  ingestion_id: prevData.ingestion_id,
  scores: {},
  avg_score: 0,
  approved: true,
  blocking: false,
  summary: parsed.summary || '',
  chunk_tags: parsed.chunk_tags || {},
  highlights: parsed.highlights || {},
  audit_findings: findings,
  backlog_to_specialists: parsed.backlog_to_specialists || [],
  questionnaire_to_human: parsed.questionnaire_to_human || [],
  issues: [],
  questions: [],
  justification: parsed.summary || '',
  metadata: {}
};
return [{ json: { personaOutput, ingestion_id: prevData.ingestion_id, findingsCount } }];
